// Get all items from the input
const items = $input.all();

// Extract Blog Topics
const blogTopics = items.map(item => item.json["Blog Topic"]);

// Find duplicates
const duplicates = blogTopics.filter((item, index) => 
  blogTopics.indexOf(item) !== index
);

// Mark items as duplicate or unique
const result = items.map(item => {
  const isDuplicate = duplicates.includes(item.json["Blog Topic"]);
  return {
    json: {
      ...item.json,
      DuplicateStatus: isDuplicate ? "Duplicate" : "Unique"
    }
  };
});

return result;

const raw = items[0].json.output;
const clean = raw.replace(/^\[|\]$/g, ''); // remove square brackets
const keywords = clean.split(/',\s*'/).map(s => s.replace(/^'/, '').replace(/'$/, '')); // split and remove extra quotes

return keywords.map(keyword => ({
  json: { keyword }
}));

const seenRows = new Set();
const uniqueItems = [];

for (const item of items) {
  const rowNum = item.json.row_number;

  if (!seenRows.has(rowNum)) {
    seenRows.add(rowNum);
    uniqueItems.push(item);
  }
}

return uniqueItems;

