return [{ json: { formattedDate } }];

const today = new Date();
const todayStr = `${(today.getMonth() + 1).toString().padStart(2, '0')}-${today.getDate().toString().padStart(2, '0')}-${today.getFullYear()}`;

const matchingItems = items.filter(item => {
