return matchingItems.length ? matchingItems : [{ json: { message: 'No blog scheduled for today', todayDate: todayStr } }];

// Get the input data
const input = $input.first();

// Check if input exists
if (!input || !input.json) {
  throw new Error('No input data received or input is not in the expected JSON format');
}

// Get the raw string from the Open AI node's output (try 'output' field)
const rawOutput = input.json.output || input.json.cleanedOutput;

// Check if rawOutput exists
if (!rawOutput) {
  throw new Error('No output or cleanedOutput field found in the input data');
}

// Split the string on newlines and filter out empty lines
const rows = rawOutput.split(/\n+/).filter(row => row.trim() !== '');

// Define the column names for the table
const columnNames = [
  'seedKeyword',
  'buyerIntentKeyword',
  'lsiKeywords',
  'blogTopic',
  'searchIntent',
  'targetAudience',
  'contentType'
];

// Map each row to an object with named fields
const outputItems = rows.map(row => {
  // Split the row into columns using the pipe (|) separator
  const columns = row.split('|').map(col => col.trim());

  // Ensure the row has the correct number of columns
  if (columns.length !== columnNames.length) {
    throw new Error(`Row does not have the expected number of columns (${columnNames.length}): ${row}`);
  }

  // Create an object with named fields
  const rowObject = {};
  columnNames.forEach((colName, index) => {
    rowObject[colName] = columns[index];
  });

  return { json: rowObject };
});

// Return the result as an array of objects
return outputItems;
